-- 从种子数据恢复：app_settings / funds / positions
-- 使用方式：psql -h 127.0.0.1 -U postgres -d gfund -f scripts/restore-seed-data.sql
-- 最后更新：2026-06-11（数据来源：011_backup_data.sql）

-- app_settings
ON CONFLICT (key) DO NOTHING;

ON CONFLICT (key) DO NOTHING;

-- funds（31条）
ON CONFLICT (code) DO NOTHING;

-- positions（31条，含实际 shares/cost_price/current_value）
ON CONFLICT (fund_code) DO NOTHING;

-- 重置序列
SELECT setval('funds_id_seq', (SELECT MAX(id) FROM funds));
SELECT setval('positions_id_seq', (SELECT MAX(id) FROM positions));
